@ARTICLE{10.3389/fimmu.2026.1758743,
	author = {Hao W and Zhai S and Zhu Q and Zhou X and Shen T and He W and Sun Y and Yang W and Yang Y},
	title = {First case of TREX1 mutation-driven retinal vasculopathy with cerebral leukoencephalopathy and systemic manifestations coexisting with lupus nephritis: a case report and mechanistic discussion.},
	journal = {Front Immunol},
	year = {2026},
	abstract = {BACKGROUND: The TREX1 gene is fundamental for the removal of cytosolic DNA and the preservation of immune tolerance. Mutations within this gene are implicated in a range of disorders, such as Retinal Vasculopathy with Cerebral Leukoencephalopathy and Systemic Manifestations (RVCL-S), Aicardi-Goutières syndrome (AGS), familial chilblain lupus, and systemic lupus erythematosus (SLE). To the best of our knowledge, this report documents the rare coexistence of TREX1-associated RVCL-S and biopsy-proven lupus nephritis in a single patient. CASE PRESENTATION: We report a case involving a middle-aged woman diagnosed with lupus nephritis, confirmed through renal biopsy, who later experienced progressive neurological deficits. Brain imaging demonstrated typical signs of cerebral leukoencephalopathy. Whole-exome sequencing uncovered a pathogenic TREX1 mutation (c.811_812dup, p.Asp272Argfs*6), resulting in a diagnosis of genetically confirmed TREX1-associated RVCL-S with an incomplete phenotype, coexisting with lupus nephritis. This case underscores a significant clinical challenge: the use of immunosuppressive therapy for lupus nephritis is hypothesized to potentially exacerbate the vascular complications associated with RVCL-S. CONCLUSION: To the best of our knowledge, this case represents the first documented instance of the TREX1 p.Asp272Argfs*6 mutation contributing to the coexistence of RVCL-S and lupus nephritis. This discovery broadens the recognized phenotypic spectrum associated with TREX1-related disorders and underscores a distinct therapeutic challenge in their management. It is important for clinicians to be aware of this new phenotype to ensure prompt diagnosis and tailored treatment strategies.},
	doi = {10.3389/fimmu.2026.1758743},
	pmid = {41939917 [Indexed for MEDLINE]},
	note = {PMC13043996}
}

@ARTICLE{10.3389/fimmu.2026.1736522,
	author = {Luo H and Chen B and Zhang X},
	title = {Novel application for the JAK inhibitor baricitinib in the treatment of Vogt-Koyanagi-Harada disease: a prospective cohort study.},
	journal = {Front Immunol},
	year = {2026},
	abstract = {PURPOSE: The purpose of this study was to prospectively evaluate the clinical efficacy and safety of baricitinib, a selective Janus kinase (JAK)1/JAK2 inhibitor, in the treatment of patients with Vogt-Koyanagi-Harada (VKH) disease. DESIGN: The study was designed as a prospective, open-label, longitudinal, single-center cohort study. METHODS: We enrolled 38 patients (76 eyes) with VKH disease (including both initial-onset and recurrent/chronic cases) at Tongji Hospital, Wuhan, China, between 2022 and 2024. Patients were assigned to one of two treatment protocols based on disease severity and prior treatment history: group A received oral baricitinib (4 mg/day) combined with systemic methylprednisolone, and group B received oral baricitinib monotherapy. Clinical assessments were performed at baseline and at 1, 3, 6, 12, and 18 months. Primary outcome measures included best-corrected visual acuity (BCVA), anterior chamber (AC) cell and flare grades, subfoveal choroidal thickness (SFCT), subretinal fluid (SRF) height, and angiographic inflammatory scores (fluorescein angiography [FA]/indocyanine green angiography [ICGA]). Secondary outcomes included quality-of-life scores (25-item version of the Visual Function Questionnaire [VFQ-25], SF-36), adverse drug reactions (ADRs), and recurrence rates. RESULTS: The cohort included 44 eyes with early-stage (initial-onset) and 32 eyes with late-stage (recurrent) VKH disease (mean age: 43.1 years ± 12.3 years; follow-up: 6-18 months). Inflammation control was achieved in all patients in both groups. In group A, the combination therapy led to rapid resolution of inflammation. In group B (monotherapy), significant improvements were observed from baseline to the final visit, including improved BCVA (0.12 to 0.68, p < 0.001), reduced AC cell grade (1.54 to 0.05, p = 0.007), decreased SFCT (537.6 to 252.4 μm, p = 0.007), and complete resolution of SRF (p < 0.001). FA and ICGA scores significantly decreased (p < 0.05), and VFQ-25 scores improved (82.6 to 92.9, p < 0.001). No severe ADRs or disease recurrences were observed during the follow-up period. CONCLUSION: This study demonstrates that baricitinib is a promising therapeutic option for both early- and late-stage VKH disease. It effectively controls choroidal inflammation, improves visual function, and allows for a substantial reduction in corticosteroid burden with a favorable safety profile. CLINICAL TRIAL REGISTRATION: http://www.chictr.org.cn, identifier ChiCTR2100048030.},
	doi = {10.3389/fimmu.2026.1736522},
	pmid = {41924279 [Indexed for MEDLINE]},
	note = {PMC13036186}
}

@ARTICLE{10.3390/biomedicines14030612,
	author = {Szeretucha M and Paczwa K, Romanowska-Próchnicka K and Ornowska S, Różycki R, Gołębiewska J},
	title = {Optical Coherence Tomography Angiography in Patients with Mixed Connective Tissue Disease.},
	journal = {Biomedicines},
	year = {2026},
	abstract = {Background: Mixed connective tissue disease (MCTD) is a rare systemic autoimmune disease which presents with clinical features that overlap with at least two connective tissue disorders, including systemic lupus erythematosus (SLE), systemic sclerosis (SSc), polymyositis (PM), dermatomyositis (DM), and rheumatoid arthritis (RA). It is characterized by the presence of anti-ribonucleoprotein (anti-U1RNP) antibodies. The mechanism of the vasculopathy associated with MCTD remains largely unknown. Optical coherence tomography angiography (OCTA) is a non-invasive imaging method of the microvasculature of the retina and choroid, providing the assessment of retinal perfusion. Objectives: The aim of the study was to evaluate the optical coherence tomography angiography (OCTA) parameters in patients with mixed connective tissue disease compared to healthy individuals. Methods: In this study, we compared the following parameters between patients with MCTD and healthy subjects: foveal avascular zone (FAZ), FAZ perimeter (PERIM), flow density (FD), choriocapillaris flow area (CCFA), outer retina flow area (ORFA), and foveal and parafoveal mean superficial and deep vessel density. Results: Parafoveal mean superficial vessel density and parafoveal mean deep vessel density were significantly lower in the MCTD group than in controls. The FAZ, FAZ PERIM, and FD values in the patients with MCTD were lower than in the control group and statistically significant for all parameters. Conclusions: The present study's findings suggest the presence of ocular vascular abnormalities in patients suffering from MCTD. These abnormalities are characterized by decreased retinal vessel density and lower choriocapillaris flow. The results of the study demonstrate the significant role of OCTA in the diagnosis and monitoring of microvascular changes in patients with MCTD.},
	doi = {10.3390/biomedicines14030612},
	pmid = {41898259},
	note = {PMC13024524}
}

